import Foundation

enum AccessibilityAnalyzerMock {
    struct Mock {
        let component: String
        let response: PromptResponse
    }
    
    static func getMock(for component: String) -> PromptResponse {
        let mocks = [transactionReviewCardMock, savingsGoalProgressCardMock, securitySettingsScreenMock]
        let firstMatch = mocks.first(where: { $0.component == component }) ?? mocks[0]
        return firstMatch.response
    }
}

